SELECT  FROM package p

WHERE 1=1

    OR p.tracking_number = #{trackingNumber}


    OR p.receiver_phone = #{phone}

ORDER BY p.in_time DESC

SELECT FROM package p
AND p.tracking_number LIKE CONCAT('%', #{trackingNumber}, '%')
AND p.pickup_code LIKE CONCAT('%', #{pickupCode}, '%')
AND p.receiver_phone LIKE CONCAT('%', #{phone}, '%')
AND p.status = #{status}
ORDER BY p.in_time DESC LIMIT #{offset}, #{size}
